+
+int main(int argc, char **argv) {
+  rclcpp::init(argc, argv);
+
+  rclcpp::NodeOptions opts{};
+
+  rclcpp::executors::SingleThreadedExecutor exec{};
+  auto pub = std::make_shared<test_composition::Publisher>(opts);
