+/**
+ * @file      main.cc
+ * @author    Sławomir Cielepak (sie@spyro-soft.com)
+ * @date      2024-12-4
+ * @copyright Copyright (c) 2024 Beam Limited. All rights reserved.
+ * 
+ * @brief   Unit tests for the Publisher and Subscriber classes.
